#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <cuda_runtime.h>

#define RADIUS 7
#define BLOCK_SIZE 256

#define CHECK_CUDA(call)                                                      \
  do {                                                                        \
    cudaError_t err__ = (call);                                               \
    if (err__ != cudaSuccess) {                                               \
      fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__,        \
              cudaGetErrorString(err__));                                     \
      exit(1);                                                                \
    }                                                                         \
  } while (0)

__global__ void stencil_kernel(const int* a, int* b, int length, int pad_size) {
  __shared__ int temp[BLOCK_SIZE + 2 * RADIUS];

  int j = threadIdx.x;
  int block_start = blockIdx.x * BLOCK_SIZE;
  int gindex = block_start + j;

  temp[j + RADIUS] = (gindex < length) ? a[gindex] : 0;

  if (j < RADIUS) {
    int left_idx = block_start + j - RADIUS;
    temp[j] = (left_idx < 0) ? 0 : ((left_idx < pad_size) ? a[left_idx] : 0);

    int right_idx = block_start + BLOCK_SIZE + j;
    temp[j + RADIUS + BLOCK_SIZE] = (right_idx < pad_size) ? a[right_idx] : 0;
  }

  __syncthreads();

  if (gindex < length) {
    int result = 0;
    #pragma unroll
    for (int offset = -RADIUS; offset <= RADIUS; offset++) {
      result += temp[j + RADIUS + offset];
    }
    b[gindex] = result;
  }
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }

  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length;
  int pad_size = (length + RADIUS);

  int* a = (int*)malloc(pad_size * sizeof(int));
  int* b = (int*)malloc(size * sizeof(int));

  for (int i = 0; i < length + RADIUS; i++) a[i] = i;

  int* d_a = nullptr;
  int* d_b = nullptr;
  CHECK_CUDA(cudaMalloc((void**)&d_a, pad_size * sizeof(int)));
  CHECK_CUDA(cudaMalloc((void**)&d_b, size * sizeof(int)));

  int num_blocks = (length + BLOCK_SIZE - 1) / BLOCK_SIZE;

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    CHECK_CUDA(cudaMemcpy(d_a, a, pad_size * sizeof(int), cudaMemcpyHostToDevice));
    stencil_kernel<<<num_blocks, BLOCK_SIZE>>>(d_a, d_b, length, pad_size);
    CHECK_CUDA(cudaGetLastError());
    CHECK_CUDA(cudaMemcpy(b, d_b, size * sizeof(int), cudaMemcpyDeviceToHost));
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  bool ok = true;
  for (int i = 0; i < 2 * RADIUS; i++) {
    int s = 0;
    for (int j = i; j <= i + 2 * RADIUS; j++)
      s += j < RADIUS ? 0 : (a[j] - RADIUS);
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2 * RADIUS; i < length; i++) {
    int s = 0;
    for (int j = i - RADIUS; j <= i + RADIUS; j++)
      s += a[j];
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  CHECK_CUDA(cudaFree(d_a));
  CHECK_CUDA(cudaFree(d_b));
  free(a);
  free(b);
  return 0;
}
